#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int counts[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &counts[i]);
        }
        int freq[N + 1] = {0};
        for (int i = 0; i < N; i++) {
            freq[counts[i]]++;
        }
        int failed = -1;
        for (int i = 0; i <= N; i++) {
            if (freq[i] == 1 && i == N - 1) {
                failed = 1;
                break;
            }
            if (freq[i] > 0 && freq[i + 1] == 1) {
                failed = N - (i + 1);
                break;
            }
        }
        printf("%d\n", failed);
    }
    return 0;
}

