import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] counts = new int[N];
            for (int i = 0; i < N; i++) {
                counts[i] = sc.nextInt();
            }
            int[] freq = new int[N + 1];
            for (int i = 0; i < N; i++) {
                freq[counts[i]]++;
            }
            int failed = -1;
            for (int i = 0; i <= N; i++) {
                if (freq[i] == 1 && i == N - 1) {
                    failed = 1;
                    break;
                }
                if (freq[i] > 0 && freq[i + 1] == 1) {
                    failed = N - (i + 1);
                    break;
                }
            }
            System.out.println(failed);
        }
    }
}

