    const freq = new Array(N + 1).fill(0);
    for (let count of counts) {
        freq[count]++;
    }
    let failed = -1;
    for (let j = 0; j <= N; j++) {
        if (freq[j] == 1 && j == N - 1) {
            failed = 1;
            break;
        }
        if (freq[j] > 0 && freq[j + 1] == 1) {
            failed = N - (j + 1);
            break;
        }
    }
    console.log(failed);
}
